    printf("1000원: %d개\n", m / 1000);
    printf("500원: %d개\n", (m % 1000) / 500);
    printf("100원: %d개\n", (m % 500) / 100);
    printf("10원: %d개\n", (m % 100) / 10);
    return 0;
}

